<?php
session_start();
require_once __DIR__ . '/../request_history_lib.php';
if (!rh_is_admin()) { header('Location: /ABRA'); exit; }
rh_check_csrf();
$error='';
if (rh_post_too_large()) { $error='Загальний розмір завантаження перевищує налаштування сервера post_max_size.'; }
if ($_SERVER['REQUEST_METHOD']==='POST' && empty($error) && ($_POST['todo'] ?? '')==='regenerate_token') {
    $case=rh_case($dbcnx,(int)($_POST['case_id'] ?? 0)); if(!$case){ http_response_code(404); die('Case not found'); }
    rh_regenerate_token($dbcnx,(int)$case['id']); header('Location: request_case.php?case_id='.(int)$case['id']); exit;
}
if ($_SERVER['REQUEST_METHOD']==='POST' && empty($error) && ($_POST['todo'] ?? '')==='add_entry') {
    $caseId=(int)($_POST['case_id'] ?? 0); $case=rh_case($dbcnx,$caseId); if(!$case || !rh_request($dbcnx,(int)$case['request_id'])){ http_response_code(404); die('Case not found'); }
    $text=trim((string)($_POST['entry_text'] ?? ''));
    $imageFiles=array_filter(rh_normalize_files('images'), function($f){ return $f['error']!==UPLOAD_ERR_NO_FILE; });
    $videoFiles=array_filter(rh_normalize_files('videos'), function($f){ return $f['error']!==UPLOAD_ERR_NO_FILE; });
    if($text==='' && count($imageFiles)===0 && count($videoFiles)===0){ $error='Додайте текст, фото або відео'; }
    else{
        $saved=array();
        try{
            $dbcnx->begin_transaction();
            $adminId=rh_admin_id(); $requestId=(int)$case['request_id'];
            $st=$dbcnx->prepare('INSERT INTO zs_request_entries (case_id, author_admin_id, entry_text, created_at, updated_at) VALUES (?, ?, ?, NOW(), NOW())'); $st->bind_param('iis',$caseId,$adminId,$text); $st->execute(); $entryId=$dbcnx->insert_id;
            foreach(array('image'=>$imageFiles,'video'=>$videoFiles) as $fileType=>$files){
                foreach($files as $file){ list($mime,$ext)=rh_validate_upload($file,$fileType); $rel=rh_storage_relative($requestId); $dir=rh_storage_root().'/'.substr($rel, strlen('request_history/')); if(!is_dir($dir) && !mkdir($dir,0755,true)) throw new Exception('Не вдалося створити каталог'); $stored=bin2hex(random_bytes(16)).'.'.$ext; $target=$dir.'/'.$stored; if(!move_uploaded_file($file['tmp_name'],$target)) throw new Exception('Не вдалося зберегти файл'); $saved[]=$target; $orig=mb_substr(basename($file['name']),0,255); $size=(int)$file['size']; $st=$dbcnx->prepare('INSERT INTO zs_request_files (entry_id, file_type, stored_name, original_name, relative_path, mime_type, file_size, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, NOW())'); $st->bind_param('isssssi',$entryId,$fileType,$stored,$orig,$rel,$mime,$size); $st->execute(); }
            }
            $st=$dbcnx->prepare('UPDATE zs_request_cases SET updated_at=NOW() WHERE id=?'); $st->bind_param('i',$caseId); $st->execute(); $dbcnx->commit(); header('Location: request_case.php?case_id='.$caseId); exit;
        }catch(Exception $e){ $dbcnx->rollback(); foreach($saved as $p){ if(is_file($p)) unlink($p); } $error=$e->getMessage(); }
    }
}
if (isset($_GET['request_id'])) { $requestId=(int)$_GET['request_id']; if(!rh_request($dbcnx,$requestId)){ http_response_code(404); die('Request not found'); } $case=rh_get_or_create_case($dbcnx,$requestId,rh_admin_id()); header('Location: request_case.php?case_id='.(int)$case['id']); exit; }
$case=rh_case($dbcnx,(int)($_GET['case_id'] ?? $_POST['case_id'] ?? 0)); if(!$case){ http_response_code(404); die('Case not found'); }
$request=rh_request($dbcnx,(int)$case['request_id']); if(!$request){ http_response_code(404); die('Request not found'); }
$entries=rh_entries($dbcnx,(int)$case['id']); $csrf=rh_csrf(); $publicUrl=rh_public_url($case['public_token']);
?>
<!doctype html>
<html lang="uk"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Робота із заявкою #<?=(int)$request['id']?></title><link href="assets/vendor/bootstrap/css/bootstrap.min.css" rel="stylesheet"><link href="assets/vendor/bootstrap-icons/bootstrap-icons.css" rel="stylesheet"><link href="assets/css/style.css" rel="stylesheet"><style>.rh-photo{max-width:180px;max-height:180px;object-fit:cover;margin:4px}.timeline-entry{border-left:3px solid #0d6efd;padding-left:15px;margin-bottom:22px}.rh-video{max-width:100%;width:420px;margin:6px 0}.file-preview span{display:inline-block;margin:2px 6px 2px 0;padding:3px 7px;background:#eef;border-radius:4px}</style></head>
<body><main class="container py-4"><a href="viewRequestMsg.php" class="btn btn-outline-secondary mb-3">← До списку заявок</a><h1>Робота із заявкою #<?=(int)$request['id']?></h1><?php if($error): ?><div class="alert alert-danger"><?=rh_h($error)?></div><?php endif; ?><div class="card mb-3"><div class="card-body"><h5 class="card-title"><?=rh_h($request['name'])?></h5><p><strong>Телефон:</strong> <?=rh_h($request['phone'])?><br><strong>Дата заявки:</strong> <?=rh_h($request['date'])?><br><strong>Об'єкт:</strong> <?=rh_h($request['lotImgDir'])?><br><strong>Опис:</strong> <?=nl2br(rh_h($request['remark']))?></p><div class="input-group mb-2"><input id="publicLink" class="form-control" readonly value="<?=rh_h($publicUrl)?>"><button class="btn btn-outline-primary" type="button" onclick="copyPublicLink()">Копіювати</button></div><form method="post" onsubmit="return confirm('Згенерувати нове посилання? Старе перестане працювати.');"><input type="hidden" name="csrf" value="<?=rh_h($csrf)?>"><input type="hidden" name="todo" value="regenerate_token"><input type="hidden" name="case_id" value="<?=(int)$case['id']?>"><button class="btn btn-outline-warning btn-sm" type="submit">Регенерувати публічний токен</button></form></div></div><div class="card mb-4"><div class="card-body"><h5 class="card-title">Додати запис</h5><form id="entryForm" method="post" enctype="multipart/form-data"><input type="hidden" name="csrf" value="<?=rh_h($csrf)?>"><input type="hidden" name="todo" value="add_entry"><input type="hidden" name="case_id" value="<?=(int)$case['id']?>"><textarea name="entry_text" class="form-control mb-3" rows="4" placeholder="Текст запису"></textarea><label class="form-label">Фотографії</label><input id="images" class="form-control mb-2" type="file" name="images[]" accept="image/jpeg,image/png,image/webp" capture="environment" multiple><label class="form-label">Відео</label><input id="videos" class="form-control mb-2" type="file" name="videos[]" accept="video/mp4,video/webm,video/quicktime" capture="environment" multiple><div id="filePreview" class="file-preview mb-3"></div><button id="submitBtn" class="btn btn-primary" type="submit">Додати запис</button><span id="uploadInfo" class="ms-2 text-muted" style="display:none">Завантаження...</span></form><p class="text-muted mt-2">Ліміти: фото до <?=rh_format_size(RH_IMAGE_MAX_SIZE)?>, відео до <?=rh_format_size(RH_VIDEO_MAX_SIZE)?>.</p></div></div><h2>Історія</h2><?php if(!$entries): ?><div class="alert alert-info">Записів ще немає.</div><?php endif; ?><?php foreach($entries as $e): ?><div class="timeline-entry"><div class="text-muted"><?=rh_h($e['created_at'])?> · <?=rh_h($e['admin_name'] ?: ('Адмін #'.$e['author_admin_id']))?></div><?php if($e['entry_text']!==''): ?><div class="mt-2"><?=nl2br(rh_h($e['entry_text']))?></div><?php endif; ?><?php foreach($e['files'] as $f): ?><?php if($f['file_type']==='image'): ?><a href="../request_history_file.php?file_id=<?=(int)$f['id']?>" target="_blank"><img class="rh-photo img-thumbnail" src="../request_history_file.php?file_id=<?=(int)$f['id']?>" alt="<?=rh_h($f['original_name'])?>"></a><?php else: ?><div><video class="rh-video" controls preload="metadata" src="../request_history_file.php?file_id=<?=(int)$f['id']?>"></video><div class="small text-muted"><?=rh_h($f['original_name'])?>, <?=rh_format_size($f['file_size'])?></div></div><?php endif; ?><?php endforeach; ?></div><?php endforeach; ?></main><script src="assets/vendor/bootstrap/js/bootstrap.bundle.min.js"></script><script>function copyPublicLink(){var el=document.getElementById('publicLink');el.select();el.setSelectionRange(0,99999);navigator.clipboard?navigator.clipboard.writeText(el.value):document.execCommand('copy');}function updatePreview(){var box=document.getElementById('filePreview');box.innerHTML='';['images','videos'].forEach(function(id){Array.from(document.getElementById(id).files).forEach(function(f){var s=document.createElement('span');s.textContent=f.name+' ('+Math.round(f.size/1024/1024*10)/10+' MB)';box.appendChild(s);});});}document.getElementById('images').addEventListener('change',updatePreview);document.getElementById('videos').addEventListener('change',updatePreview);document.getElementById('entryForm').addEventListener('submit',function(){document.getElementById('submitBtn').disabled=true;document.getElementById('uploadInfo').style.display='inline';});</script></body></html>